CREATE TABLE stock_movements (id TEXT PRIMARY KEY, item_id TEXT NOT NULL REFERENCES items(id), from_warehouse_id TEXT REFERENCES warehouses(id), to_warehouse_id TEXT NOT NULL REFERENCES warehouses(id), quantity INTEGER NOT NULL, movement_type TEXT NOT NULL CHECK(movement_type IN ('receipt','transfer','pick','adjustment','return')), reference_type TEXT, reference_id TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')));
